import React, { useState } from "react";
import styles from "./nav-bar.module.css";
import NavButton from "../nav-button";
import MegaMenu from "../mega-menu";
import dataList from "../../nav-list/nav-list.json";

const NavBar: React.FC = () => {
  const [activeDropdown, setActiveDropdown] = useState<string>("");

  // Function to toggle the active dropdown
  const toggleDropDown = (dropdownName: string): void => {
    setActiveDropdown(activeDropdown === dropdownName ? "" : dropdownName);
  };

  // Define dropdown content objects
  const discoveryDropdownContent = dataList.find(
    (item) => item.title === "Discovery"
  )?.items;

  const aboutDropdownContent = dataList.find(
    (item) => item.title === "About"
  )?.items;

  return (
    <>
      <div className={styles.nav__bar}>
        <NavButton
          text="Discovery"
          handleClick={() => toggleDropDown("Discovery")}
        />
        <NavButton
          text="About"
          handleClick={() => toggleDropDown("About")}
        />
        <NavButton text="Contact us" href="/contact" isLink={true} />
      </div>

      {/* Render the MegaMenu components based on the active dropdown */}
      {activeDropdown === "Discovery" && (
        <MegaMenu dropDownObject={discoveryDropdownContent || []} show={true} />
      )}
      {activeDropdown === "About" && (
        <MegaMenu dropDownObject={aboutDropdownContent || []} show={true} />
      )}
    </>
  );
};

export default NavBar;




